import collections

# 1. Sabit Boyutlu Dizi (Python listesi doğrudan indeks erişimi için)
# O(1) erişim
class O1ArrayAccess:
    def __init__(self, size):
        self._data = [None] * size

    def get_at_index(self, index):
        if 0 <= index < len(self._data):
            return self._data[index]
        raise IndexError("Index out of bounds")

    def set_at_index(self, index, value):
        if 0 <= index < len(self._data):
            self._data[index] = value
        else:
            raise IndexError("Index out of bounds")

# 2. Hash Tablosu (Python dict/set - Ortalama O(1) ekleme, silme, arama)
class O1HashTable:
    def __init__(self):
        self._data = {} # Python dict is a hash table

    def insert(self, key, value): # Ortalama O(1)
        self._data[key] = value

    def get(self, key): # Ortalama O(1)
        return self._data.get(key)

    def delete(self, key): # Ortalama O(1)
        if key in self._data:
            del self._data[key]

# 3. Çift Uçlu Kuyruk (collections.deque - O(1) her iki uçtan ekleme/silme)
class O1Deque:
    def __init__(self):
        self._data = collections.deque()

    def add_front(self, item): # O(1)
        self._data.appendleft(item)

    def remove_front(self): # O(1)
        if self._data:
            return self._data.popleft()
        return None

    def add_back(self, item): # O(1)
        self._data.append(item)

    def remove_back(self): # O(1)
        if self._data:
            return self._data.pop()
        return None

# 4. Çift Yönlü Bağlı Liste (Kendi uygulamamız - O(1) başa/sona ekleme/silme)
class _Node:
    def __init__(self, data):
        self.data = data
        self.next = None
        self.prev = None

class O1DoublyLinkedList:
    def __init__(self):
        self.head = None
        self.tail = None

    def add_front(self, data): # O(1)
        new_node = _Node(data)
        if not self.head:
            self.head = self.tail = new_node
        else:
            new_node.next = self.head
            self.head.prev = new_node
            self.head = new_node

    def remove_front(self): # O(1)
        if not self.head:
            return None
        data = self.head.data
        if self.head == self.tail: # Only one node
            self.head = self.tail = None
        else:
            self.head = self.head.next
            self.head.prev = None
        return data

    def add_back(self, data): # O(1)
        new_node = _Node(data)
        if not self.tail:
            self.head = self.tail = new_node
        else:
            new_node.prev = self.tail
            self.tail.next = new_node
            self.tail = new_node

    def remove_back(self): # O(1)
        if not self.tail:
            return None
        data = self.tail.data
        if self.head == self.tail: # Only one node
            self.head = self.tail = None
        else:
            self.tail = self.tail.prev
            self.tail.next = None
        return data

if __name__ == "__main__":
    # O1ArrayAccess kullanımı
    my_array = O1ArrayAccess(5)
    my_array.set_at_index(2, "Merhaba")
    print(f"O1ArrayAccess[2]: {my_array.get_at_index(2)}") # Çıktı: Merhaba

    # O1HashTable kullanımı
    my_hash_table = O1HashTable()
    my_hash_table.insert("anahtar1", "değer1")
    my_hash_table.insert("anahtar2", "değer2")
    print(f"O1HashTable['anahtar1']: {my_hash_table.get('anahtar1')}") # Çıktı: değer1
    my_hash_table.delete("anahtar1")
    print(f"O1HashTable['anahtar1'] silindi mi?: {my_hash_table.get('anahtar1')}") # Çıktı: None

    # O1Deque kullanımı
    my_deque = O1Deque()
    my_deque.add_front(1)
    my_deque.add_back(2)
    my_deque.add_front(0)
    print(f"O1Deque remove_front: {my_deque.remove_front()}") # Çıktı: 0
    print(f"O1Deque remove_back: {my_deque.remove_back()}") # Çıktı: 2

    # O1DoublyLinkedList kullanımı
    my_dll = O1DoublyLinkedList()
    my_dll.add_front("A")
    my_dll.add_back("C")
    my_dll.add_front("B") # Liste: B -> A -> C
    print(f"O1DoublyLinkedList remove_front: {my_dll.remove_front()}") # Çıktı: B
    print(f"O1DoublyLinkedList remove_back: {my_dll.remove_back()}") # Çıktı: C
